const input = items[0].json;
const result = [];

// Usamos la lista de nombres como base para el largo del array
input.nombre.forEach((name, index) => {
  result.push({
    json: {
      titulo: name,
      precio: input.precio[index] || "N/A",
      // Si la imagen es un SVG transparente, intentamos que no sea ese el valor
      imagen: input.imagen[index]
    }
  });
});

return result;

