const html = $input.first().json.data;

// Elimina scripts, estilos y etiquetas HTML
const clean = html
  .replace(/<script[^>]*>[\s\S]*?<\/script>/gi, '')
  .replace(/<style[^>]*>[\s\S]*?<\/style>/gi, '')
  .replace(/<[^>]+>/g, ' ')
  .replace(/\s+/g, ' ')
  .trim()
  .substring(0, 12000); // Limita a 12k caracteres

return [{ json: { text: clean } }];
